async function seedEmailTemplates() {
  console.log("Seeding email templates...\n");

  let created = 0;
  let updated = 0;

  for (const tpl of templates) {
    const existing = await prisma.emailTemplate.findUnique({
      where: { slug: tpl.slug },
    });

    const result = await prisma.emailTemplate.upsert({
      where: { slug: tpl.slug },
      update: {
        name: tpl.name,
        subject: tpl.subject,
        html_content: tpl.html_content,
        variables: tpl.variables,
        category: tpl.category,
      },
      create: {
        slug: tpl.slug,
        name: tpl.name,
        subject: tpl.subject,
        html_content: tpl.html_content,
        variables: tpl.variables,
        category: tpl.category,
      },
    });

    if (existing) {
      console.log(`  UPDATED: "${tpl.slug}" (id: ${result.id})`);
      updated++;
    } else {
      console.log(`  CREATED: "${tpl.slug}" (id: ${result.id})`);
      created++;
    }
  }

  console.log(`\nDone! Created: ${created}, Updated: ${updated}, Total: ${templates.length}`);
}

seedEmailTemplates()
  .catch((error) => {
    console.error("Seed failed:", error);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
